patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 19b95cf473e9..dd437ae449f6 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -7781,6 +7781,9 @@ unsigned BoUpSLP::canMapToVector(Type *T) const {

   while (isa<StructType, ArrayType, FixedVectorType>(EltTy)) {
     if (auto *ST = dyn_cast<StructType>(EltTy)) {
+      // Empty structs cannot be mapped to vectors.
+      if (ST->getNumElements() == 0)
+        return 0;
       // Check that struct is homogeneous.
       for (const auto *Ty : ST->elements())
         if (Ty != *ST->element_begin())
@@ -7788,6 +7791,9 @@ unsigned BoUpSLP::canMapToVector(Type *T) const {
       N *= ST->getNumElements();
       EltTy = *ST->element_begin();
     } else if (auto *AT = dyn_cast<ArrayType>(EltTy)) {
+      // Empty arrays cannot be mapped to vectors.
+      if (AT->getNumElements() == 0)
+        return 0;
       N *= AT->getNumElements();
       EltTy = AT->getElementType();
     } else {
@@ -7799,6 +7805,9 @@ unsigned BoUpSLP::canMapToVector(Type *T) const {

   if (!isValidElementType(EltTy))
     return 0;
+  // If MinVecRegSize > MaxVecRegSize, vectorization isn't feasible for this target.
+  if (MinVecRegSize > MaxVecRegSize)
+    return 0;
   uint64_t VTSize = DL->getTypeStoreSizeInBits(getWidenedType(EltTy, N));
   if (VTSize < MinVecRegSize || VTSize > MaxVecRegSize ||
       VTSize != DL->getTypeStoreSizeInBits(T))

